VALUES
  ('pukao-e3452428-moex-00575', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '若比較縣與鄉（鎮、市）自治事項，何者僅屬於縣，而不屬鄉（鎮、市）自治事項之範疇？', '["事業之經營及管理事項", "公共安全事項", "都市計畫事項", "社會服務事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00576', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '直轄市政府或縣（市）政府辦理自治事項如違背憲法、法律或基於法律授權之法規，應以何等行 政程序加以撤銷、變更、廢止或停止其執行？', '["由監察院提出糾正後，會同行政院作成上開處分", "由中央主管機關陳報行政院做成上開處分", "由中央主管機關依其職權做成上開處分", "對於直轄市政府、縣（市）政府所辦理之自治事項，分別由行政院、內政部做成上開處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00577', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '地方議會議長或代表會主席如有失職之情事，應如何監督糾正？', '["由監察院提出彈劾，移送懲戒法院懲戒", "由議員或代表依法罷免之", "均由檢察機關偵辦起訴", "由上級監督機關解除其職務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00578', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依地方制度法規定，關於地方行政機關之組織編制，下列敘述何者正確？', '["縣劃分為區，置區長及副區長各1人，由縣長依法任用", "縣（市）政府置主任秘書1人，由縣（市）長以機要人員方式進用", "直轄市人口在 20 萬人以上之區，其區公所除區長外，並得置副區長 1 人，原則上由市長依公 務人員任用法任免之", "人口在200萬人以上之直轄市，其市政府得增置副秘書長1人，由秘書長依法任免之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00579', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '關於直轄市區公所之建置，下列敘述何者錯誤？', '["直轄市劃分為區，區設區公所", "直轄市之區公所置區長1人，由市長依法任用", "直轄市山地原住民區，設區民代表會及區公所，分別為山地原住民區之立法機關及行政機關", "直轄市山地原住民區，為直轄市政府之派出機關，承市長之命綜理區政"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00580', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依地方制度法規定，關於地方立法機關之會期，下列敘述何者正確？', '["直轄市議會定期會每6個月開會1次，每次包括例假日或停會在內，不得超過60日", "鄉（鎮、市）民代表會代表總額20人以下者，其定期會每次會期包括例假日或停會在內，不得 超過15日", "直轄市議會每年審議總預算之定期會，會期屆滿而議案尚未議畢時，得應直轄市長之要求而延 長會期，但不得超過12日", "直轄市議會經直轄市長之請求，得召集臨時會，其會期包括例假日或停會在內，每次不得超過 10日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00581', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '甲為某直轄市議會之議長，關於其選舉、罷免方式之敘述，下列何者正確？', '["該市議會議長之選舉及罷免，均應由議員以不記名投票方式為之", "甲之當選議長，需取得議員總額過半數之出席，以及出席總數三分之二以上之得票", "對於甲之罷免，需經議員總額過半數之出席，以及出席總數三分之二以上之同意", "甲就職議長後，如尚未滿2年者，依法不得予以罷免"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00582', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '直轄市議會未於會計年度開始後3個月內完成總預算案之審議。依地方制度法規定，關於直轄市 政府之處理方式，下列敘述何者錯誤？', '["收入部分暫依上年度標準及實際發生數，覈實收入", "非新增之支出科目，得依上年度執行數，覈實動支", "將總預算案未審議完成部分報請行政院，邀集各有關機關協商", "將原提總預算案未審議完成部分，報請行政院動支預備金因應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00583', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '縣與鄉（鎮、市）間，就有關環境保護之自治事項遇有爭議時，依地方制度法得為如何之處理？', '["由內政部解決之", "由行政院環境保護署解決之", "由縣議會議決之", "由內政部會同行政院環境保護署解決之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00584', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關地方機關之組織法令，下列敘述何者正確？', '["內政部就地方行政及立法機關組織事宜，訂定發布有地方行政機關組織準則及地方立法機關組 織準則", "各直轄市政府、直轄市議會均分別擬定組織自治條例並報行政院核定後實施", "直轄市、縣（市）政府及其所屬機關之組織法令名稱，均為組織自治條例", "鄉（鎮、市）公所及鄉（鎮、市）民代表會，均係以組織規程之名稱作為其組織法令"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
